import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.CMYkYJvz.js";const u=JSON.parse('{"title":"Scripting","description":"QuickJS scripting capabilities, restrictions, and usage.","frontmatter":{"title":"Scripting","description":"QuickJS scripting capabilities, restrictions, and usage.","editLink":false},"headers":[],"relativePath":"en/reference/scripting.md","filePath":"en/reference/scripting.md"}'),s={name:"en/reference/scripting.md"};function c(r,e,n,d,p,l){return a(),i("div",null,[...e[0]||(e[0]=[o('<blockquote><p>This page is automatically synced from <code>docs-en/scripts.md</code>. Language: <strong>English</strong> | <a href="./../../reference/scripting">中文</a></p></blockquote><h1 id="scripts-management-and-development-guide" tabindex="-1">Scripts Management and Development Guide <a class="header-anchor" href="#scripts-management-and-development-guide" aria-label="Permalink to &quot;Scripts Management and Development Guide&quot;">​</a></h1><p>The Admin UI Scripts module manages request, response, decode, and parser scripts. Scripts are stored on disk and executed by the QuickJS sandbox.</p><h2 id="script-types" tabindex="-1">Script Types <a class="header-anchor" href="#script-types" aria-label="Permalink to &quot;Script Types&quot;">​</a></h2><ol><li>Request Script: runs before forwarding to upstream and can modify method, headers, or body.</li><li>Response Script: runs after receiving upstream response and can modify status, headers, or body.</li><li>Decode Script: decodes, redacts, or formats body content before display and persistence.</li><li>Parser Script: used with <code>bp://...</code> and <code>decode://bp</code> for binary protocol parsing. It affects stored and displayed traffic, not the actual client/upstream stream.</li></ol><h2 id="naming" tabindex="-1">Naming <a class="header-anchor" href="#naming" aria-label="Permalink to &quot;Naming&quot;">​</a></h2><p>Script names map to <code>{data_dir}/scripts/{type}/{name}.js</code>. Names may include <code>/</code> for directory hierarchy. They must be non-empty, at most 128 characters, must not start or end with <code>/</code>, must not contain <code>..</code> or <code>//</code>, and may only use letters, digits, <code>-</code>, <code>_</code>, and <code>/</code>.</p><h2 id="runtime-objects" tabindex="-1">Runtime Objects <a class="header-anchor" href="#runtime-objects" aria-label="Permalink to &quot;Runtime Objects&quot;">​</a></h2><ul><li><code>ctx</code>: request id, script name, script type, Values, matched rules, and phase.</li><li><code>log</code> / <code>console</code>: logs visible in the UI.</li><li><code>file</code>: sandboxed file API.</li><li><code>net</code>: optional network API with limits.</li><li><code>request</code> / <code>response</code>: phase-specific mutable traffic objects.</li></ul><p>QuickJS execution is synchronous; <code>async/await</code> is not supported.</p>',10)])])}const h=t(s,[["render",c]]);export{u as __pageData,h as default};
